1	<?php
2	declare(strict_types=1);
3	
4	namespace app\service;
5	
6	use think\facade\Db;
7	
8	/**
9	 * Payment posting with idempotency and invoice status update.
10	 */
11	class PaymentService
12	{
13	    private const IDEMP_WINDOW_SECONDS = 600; // 10 minutes
14	
15	    public static function post(array $data, array $user, string $idempotencyKey, string $traceId = ''): array
16	    {
17	        $invoiceId = (int)($data['invoice_id'] ?? 0);
18	        $amountCents = (int)($data['amount_cents'] ?? 0);
19	        $paidAt = $data['paid_at'] ?? date('Y-m-d H:i:s');
20	        $method = $data['method'] ?? 'cash';
21	
22	        if ($invoiceId <= 0) throw new \think\exception\HttpException(400, 'invoice_id is required');
23	        if ($amountCents <= 0) throw new \think\exception\HttpException(400, 'amount_cents must be positive');
24	
25	        // Check idempotency replay
26	        $scopeKey = self::buildScopeKey('POST', '/payments', $user['id'], $idempotencyKey);
27	        $existing = self::checkIdempotency($scopeKey);
28	        if ($existing) {
29	            return $existing;
30	        }
31	
32	        // Verify invoice
33	        $invoice = Db::table('invoices')->where('id', $invoiceId)->find();
34	        if (!$invoice) throw new \think\exception\HttpException(404, 'Invoice not found');
35	
36	        // Scope check via contract
37	        $contract = Db::table('contracts')->where('id', $invoice['contract_id'])->find();
38	        if (!$contract || !ScopeService::canAccess($user, $contract['geo_scope_level'], (int)$contract['geo_scope_id'])) {
39	            throw new \think\exception\HttpException(403, 'Invoice outside your scope');
40	        }
41	
42	        if ($invoice['status'] === 'paid') {
43	            throw new \think\exception\HttpException(409, 'Invoice already paid');
44	        }
45	
46	        // Encrypt sensitive bank reference if provided (prompt: AES-256 at rest)
47	        $reference = $data['reference'] ?? null;
48	        $referenceEnc = !empty($reference) ? EncryptionService::encrypt((string)$reference) : null;
49	
50	        // Record payment
51	        $paymentId = Db::table('payments')->insertGetId([
52	            'invoice_id'  => $invoiceId,
53	            'amount_cents' => $amountCents,
54	            'paid_at'     => $paidAt,
55	            'method'      => $method,
56	            'reference_enc' => $referenceEnc,
57	            'posted_by'   => $user['id'],
58	        ]);
59	
60	        // Transition invoice to paid
61	        $beforeInvoice = ['status' => $invoice['status'], 'amount_cents' => $invoice['amount_cents']];
62	        InvoiceService::transition($invoiceId, 'paid', $traceId);
63	
64	        // Get final balance
65	        $totalPaid = (int)Db::table('payments')->where('invoice_id', $invoiceId)->sum('amount_cents');
66	        $totalRefunded = (int)Db::table('refunds')->where('invoice_id', $invoiceId)->sum('amount_cents');
67	        $balanceCents = (int)$invoice['amount_cents'] - $totalPaid + $totalRefunded;
68	
69	        $result = [
70	            'payment_id'     => $paymentId,
71	            'invoice_status' => 'paid',
72	            'balance_cents'  => max($balanceCents, 0),
73	        ];
74	
75	        // Store idempotency record
76	        self::storeIdempotency($scopeKey, $user['id'], 201, $result);
77	
78	        LogService::info('payment_posted', ['payment_id' => $paymentId, 'invoice_id' => $invoiceId], $traceId);
79	
80	        // Append-only audit log (prompt: payment actions with before/after values)
81	        AuditService::log(
82	            'payment_posted',
83	            (int)$user['id'],
84	            'invoice',
85	            $invoiceId,
86	            $beforeInvoice,
87	            ['status' => 'paid', 'payment_id' => $paymentId, 'amount_cents' => $amountCents, 'method' => $method, 'balance_cents' => max($balanceCents, 0)],
88	            RequestContext::ip(),
89	            RequestContext::device(),
90	            $traceId
91	        );
92	
93	        return $result;
94	    }
95	
96	    public static function getReceipt(int $invoiceId, array $user): array
97	    {
98	        $invoice = Db::table('invoices')->where('id', $invoiceId)->find();
99	        if (!$invoice) throw new \think\exception\HttpException(404, 'Invoice not found');
100	
101	        $contract = Db::table('contracts')->where('id', $invoice['contract_id'])->find();
102	        if (!$contract || !ScopeService::canAccess($user, $contract['geo_scope_level'], (int)$contract['geo_scope_id'])) {
103	            throw new \think\exception\HttpException(403, 'Outside your scope');
104	        }
105	
106	        $payments = Db::table('payments')->where('invoice_id', $invoiceId)->select()->toArray();
107	        return ['invoice' => $invoice, 'contract' => $contract, 'payments' => $payments];
108	    }
109	
110	    private static function buildScopeKey(string $method, string $route, int $actorId, string $key): string
111	    {
112	        return $method . '|' . $route . '|' . $actorId . '|' . $key;
113	    }
114	
115	    private static function checkIdempotency(string $scopeKey): ?array
116	    {
117	        $parts = explode('|', $scopeKey);
118	        $cutoff = date('Y-m-d H:i:s', time() - self::IDEMP_WINDOW_SECONDS);
119	
120	        $record = Db::table('payment_idempotency')
121	            ->where('actor_id', (int)$parts[2])
122	            ->where('method', $parts[0])
123	            ->where('route', $parts[1])
124	            ->where('idempotency_key', $parts[3])
125	            ->where('created_at', '>=', $cutoff)
126	            ->find();
127	
128	        if ($record) {
129	            return json_decode($record['response_json'], true);
130	        }
131	        return null;
132	    }
133	
134	    private static function storeIdempotency(string $scopeKey, int $actorId, int $status, array $response): void
135	    {
136	        $parts = explode('|', $scopeKey);
137	        try {
138	            Db::table('payment_idempotency')->insert([
139	                'actor_id'        => $actorId,
140	                'method'          => $parts[0],
141	                'route'           => $parts[1],
142	                'idempotency_key' => $parts[3],
143	                'response_status' => $status,
144	                'response_json'   => json_encode($response),
145	            ]);
146	        } catch (\Throwable $e) {
147	            // Duplicate key — already stored
148	        }
149	    }
150	}
