4	namespace app\service;
5	
6	use think\facade\Db;
7	
8	/**
9	 * Invoice lifecycle service.
10	 * State machine: unpaid -> paid, unpaid -> overdue.
11	 * No other transitions valid (returns 409).
12	 * Snapshots are immutable records of invoice state at transition points.
13	 */
14	class InvoiceService
15	{
16	    private const VALID_TRANSITIONS = [
17	        'unpaid' => ['paid', 'overdue'],
18	    ];
19	
20	    public static function list(array $user, array $filters = []): array
21	    {
22	        $query = Db::table('invoices')
23	            ->alias('i')
24	            ->join('contracts c', 'i.contract_id = c.id')
25	            ->field('i.*');
26	
27	        // Qualify scope column with `c.` alias to avoid ambiguity in joined query
28	        $query = ScopeService::applyScope($query->where('1=1'), $user, 'c.geo_scope_id');
29	
30	        if (!empty($filters['contract_id'])) $query->where('i.contract_id', (int)$filters['contract_id']);
31	        if (!empty($filters['status'])) $query->where('i.status', $filters['status']);
32	        if (!empty($filters['due_from'])) $query->where('i.due_date', '>=', $filters['due_from']);
33	        if (!empty($filters['due_to'])) $query->where('i.due_date', '<=', $filters['due_to']);
34	
35	        $page = max((int)($filters['page'] ?? 1), 1);
36	        $size = min(max((int)($filters['size'] ?? 20), 1), 100);
37	
38	        $total = $query->count();
39	        $items = $query->order('i.due_date', 'asc')->limit(($page - 1) * $size, $size)->select()->toArray();
40	
41	        return ['items' => $items, 'page' => $page, 'total' => $total];
42	    }
43	
44	    public static function getById(int $id, array $user): array
45	    {
46	        $invoice = Db::table('invoices')->where('id', $id)->find();
47	        if (!$invoice) throw new \think\exception\HttpException(404, 'Invoice not found');
48	
49	        $contract = Db::table('contracts')->where('id', $invoice['contract_id'])->find();
50	        if (!$contract || !ScopeService::canAccess($user, $contract['geo_scope_level'], (int)$contract['geo_scope_id'])) {
51	            throw new \think\exception\HttpException(403, 'Invoice outside your scope');
52	        }
53	
54	        $snapshot = Db::table('invoice_snapshots')
55	            ->where('invoice_id', $id)
56	            ->order('id', 'desc')
57	            ->find();
58	
59	        return ['invoice' => $invoice, 'snapshot' => $snapshot];
60	    }
61	
62	    /**
63	     * Transition an invoice to a new status.
64	     * Validates state machine. Creates snapshot on transition.
65	     */
66	    public static function transition(int $invoiceId, string $newStatus, string $traceId = ''): array
67	    {
68	        $invoice = Db::table('invoices')->where('id', $invoiceId)->find();
69	        if (!$invoice) throw new \think\exception\HttpException(404, 'Invoice not found');
70	
71	        $current = $invoice['status'];
72	        $allowed = self::VALID_TRANSITIONS[$current] ?? [];
73	        if (!in_array($newStatus, $allowed, true)) {
74	            throw new \think\exception\HttpException(409,
75	                "Invalid invoice transition from '{$current}' to '{$newStatus}'"
76	            );
77	        }
78	
79	        $newVersion = (int)$invoice['snapshot_version'] + 1;
80	        Db::table('invoices')->where('id', $invoiceId)->update([
81	            'status'           => $newStatus,
82	            'snapshot_version' => $newVersion,
83	        ]);
84	
85	        self::createSnapshot($invoiceId);
86	
87	        LogService::info('invoice_transition', [
88	            'invoice_id' => $invoiceId,
89	            'from'       => $current,
90	            'to'         => $newStatus,
91	        ], $traceId);
92	
93	        return ['id' => $invoiceId, 'status' => $newStatus, 'snapshot_version' => $newVersion];
94	    }
95	
96	    /**
97	     * Mark overdue invoices (unpaid past due date). Called by daily job or endpoint.
98	     */
99	    public static function markOverdue(string $traceId = ''): int
100	    {
101	        $today = date('Y-m-d');
102	        $overdueInvoices = Db::table('invoices')
103	            ->where('status', 'unpaid')
104	            ->where('due_date', '<', $today)
105	            ->select()
106	            ->toArray();
107	
108	        $count = 0;
109	        foreach ($overdueInvoices as $inv) {
110	            try {
111	                self::transition((int)$inv['id'], 'overdue', $traceId);
112	                $count++;
113	            } catch (\Throwable $e) {
114	                // Skip already transitioned
115	            }
116	        }
117	        return $count;
118	    }
119	
120	    /**
121	     * Create an immutable snapshot of the current invoice state.
122	     */
123	    public static function createSnapshot(int $invoiceId): void
124	    {
125	        $invoice = Db::table('invoices')->where('id', $invoiceId)->find();
126	        if (!$invoice) return;
127	
128	        Db::table('invoice_snapshots')->insert([
129	            'invoice_id'    => $invoiceId,
130	            'snapshot_json' => json_encode($invoice),
131	        ]);
132	    }
133	
134	    /**
135	     * Get snapshot — snapshots are read-only, never updated.
136	     */
137	    public static function getSnapshot(int $snapshotId): ?array
138	    {
139	        return Db::table('invoice_snapshots')->where('id', $snapshotId)->find();
140	    }
141	}
