4	namespace app\service;
5	
6	/**
7	 * Late fee calculator.
8	 * Rule: 5-day grace period, then 1.5% per month applied daily (0.05%/day).
9	 * Cap: $250.00 per invoice = 25000 cents.
10	 * All math in integer cents — no floats.
11	 */
12	class LateFeeService
13	{
14	    private const GRACE_DAYS = 5;
15	    private const DAILY_RATE_BPS = 5; // 0.05% = 5 basis points
16	    private const CAP_CENTS = 25000;  // $250.00
17	
18	    /**
19	     * Calculate late fee in cents.
20	     * @param int $amountCents Invoice amount in cents
21	     * @param int $daysOverdue Total days past due date
22	     * @return int Late fee in cents (0 if within grace, capped at 25000)
23	     */
24	    public static function calculate(int $amountCents, int $daysOverdue): int
25	    {
26	        if ($daysOverdue <= self::GRACE_DAYS) {
27	            return 0;
28	        }
29	
30	        $chargeableDays = $daysOverdue - self::GRACE_DAYS;
31	        // fee = amountCents * 0.0005 * chargeableDays
32	        // Using integer math: fee = amountCents * 5 * chargeableDays / 10000
33	        $fee = intdiv($amountCents * self::DAILY_RATE_BPS * $chargeableDays, 10000);
34	
35	        return min($fee, self::CAP_CENTS);
36	    }
37	
38	    public static function getGraceDays(): int { return self::GRACE_DAYS; }
39	    public static function getCapCents(): int { return self::CAP_CENTS; }
40	}
