4	namespace app\service;
5	
6	use think\facade\Db;
7	
8	/**
9	 * Entity profile CRUD service.
10	 * Manages farmer/enterprise/collective profiles with configurable extra fields,
11	 * geo scope enforcement, and duplicate detection.
12	 */
13	class EntityService
14	{
15	    private const VALID_TYPES = ['farmer', 'enterprise', 'collective'];
16	
17	    /**
18	     * Issue #10 remediation: validate extra_fields against the
19	     * admin-configured `extra_field_definitions` for the given entity_type.
20	     *
21	     * Rules enforced:
22	     *  - Unknown keys are rejected (400).
23	     *  - text: must be a string.
24	     *  - number: must be numeric (int or float).
25	     *  - date: must match YYYY-MM-DD and parse to a real date.
26	     *  - select: value must appear in options_json.
27	     * Only definitions with active=1 are considered.
28	     *
29	     * @throws \think\exception\HttpException on any violation.
30	     */
31	    public static function validateExtraFields(string $entityType, ?array $extraFields): void
32	    {
33	        if (empty($extraFields)) {
34	            return;
35	        }
36	
37	        $defs = Db::table('extra_field_definitions')
38	            ->where('entity_type', $entityType)
39	            ->where('active', 1)
40	            ->select()
41	            ->toArray();
42	
43	        $byKey = [];
44	        foreach ($defs as $d) {
45	            $byKey[$d['field_key']] = $d;
46	        }
47	
48	        foreach ($extraFields as $key => $value) {
49	            if (!isset($byKey[$key])) {
50	                throw new \think\exception\HttpException(400,
51	                    "unknown extra field '{$key}' for entity_type={$entityType}"
52	                );
53	            }
54	            $def = $byKey[$key];
55	            $type = $def['field_type'];
56	
57	            switch ($type) {
58	                case 'text':
59	                    if (!is_string($value)) {
60	                        throw new \think\exception\HttpException(400,
61	                            "extra field '{$key}' must be a string"
62	                        );
63	                    }
64	                    break;
65	                case 'number':
66	                    if (!is_numeric($value)) {
67	                        throw new \think\exception\HttpException(400,
68	                            "extra field '{$key}' must be numeric"
69	                        );
70	                    }
71	                    break;
72	                case 'date':
73	                    if (!is_string($value) || !preg_match('/^\d{4}-\d{2}-\d{2}$/', $value)) {
74	                        throw new \think\exception\HttpException(400,
75	                            "extra field '{$key}' must be YYYY-MM-DD"
76	                        );
77	                    }
78	                    $parts = explode('-', $value);
79	                    if (!checkdate((int)$parts[1], (int)$parts[2], (int)$parts[0])) {
80	                        throw new \think\exception\HttpException(400,
81	                            "extra field '{$key}' is not a valid date"
82	                        );
83	                    }
84	                    break;
85	                case 'select':
86	                    $options = !empty($def['options_json']) ? json_decode($def['options_json'], true) : [];
87	                    if (!is_array($options) || !in_array($value, $options, true)) {
88	                        throw new \think\exception\HttpException(400,
89	                            "extra field '{$key}' must be one of: " . implode(', ', $options ?: [])
90	                        );
91	                    }
92	                    break;
93	                default:
94	                    throw new \think\exception\HttpException(400,
95	                        "extra field '{$key}' has unknown definition type"
96	                    );
97	            }
98	        }
99	    }
100	
101	    /**
102	     * List entities with scope filtering and pagination.
103	     */
104	    public static function list(array $user, array $filters = []): array
105	    {
106	        $query = Db::table('entity_profiles')->where('status', 'active');
107	
108	        // Apply geo scope
109	        $query = ScopeService::applyScope($query, $user);
110	
111	        // Optional filters
112	        if (!empty($filters['entity_type'])) {
113	            $query->where('entity_type', $filters['entity_type']);
114	        }
115	        if (!empty($filters['keyword'])) {
116	            $query->whereLike('display_name', '%' . $filters['keyword'] . '%');
117	        }
118	
119	        $page = max((int)($filters['page'] ?? 1), 1);
120	        $size = min(max((int)($filters['size'] ?? 20), 1), 100);
121	        $offset = ($page - 1) * $size;
122	
123	        $total = $query->count();
124	        $items = $query->order('created_at', 'desc')
125	            ->limit($offset, $size)
126	            ->select()
