315	    /**
316	     * Merge two profiles: source into target.
317	     */
318	    public static function merge(int $sourceId, int $targetId, array $resolutionMap, array $user, string $traceId = ''): array
319	    {
320	        $source = Db::table('entity_profiles')->where('id', $sourceId)->find();
321	        $target = Db::table('entity_profiles')->where('id', $targetId)->find();
322	
323	        if (!$source || !$target) {
324	            throw new \think\exception\HttpException(404, 'Profile not found');
325	        }
326	
327	        // Scope check both
328	        if (!ScopeService::canAccess($user, $source['geo_scope_level'], (int)$source['geo_scope_id']) ||
329	            !ScopeService::canAccess($user, $target['geo_scope_level'], (int)$target['geo_scope_id'])) {
330	            throw new \think\exception\HttpException(403, 'Access denied: profiles outside your scope');
331	        }
332	
333	        // Record merge history
334	        $historyId = Db::table('profile_merge_history')->insertGetId([
335	            'source_profile_id' => $sourceId,
336	            'target_profile_id' => $targetId,
337	            'merged_by'         => $user['id'],
338	            'diff_json'         => json_encode([
339	                'source' => $source,
340	                'target' => $target,
341	                'resolution' => $resolutionMap,
342	            ]),
343	        ]);
344	
345	        // Deactivate source
346	        Db::table('entity_profiles')
347	            ->where('id', $sourceId)
348	            ->update(['status' => 'inactive']);
349	
350	        // Close related duplicate flags
351	        Db::table('duplicate_flags')
352	            ->where(function ($q) use ($sourceId, $targetId) {
353	                $q->where('left_profile_id', $sourceId)->where('right_profile_id', $targetId);
354	            })
355	            ->whereOr(function ($q) use ($sourceId, $targetId) {
356	                $q->where('left_profile_id', $targetId)->where('right_profile_id', $sourceId);
357	            })
358	            ->update(['status' => 'merged']);
359	
360	        LogService::info('entity_merged', [
361	            'source_id' => $sourceId,
362	            'target_id' => $targetId,
363	        ], $traceId);
364	
365	        return [
366	            'merged_profile_id'   => $targetId,
367	            'change_history_id'   => $historyId,
368	        ];
369	    }
370	}
