91	    /**
92	     * Issue #11 remediation: Excel (.xlsx) output.
93	     *
94	     * Generates a minimal valid Office Open XML Spreadsheet workbook
95	     * (.xlsx) using PHP's bundled ZipArchive. No third-party library
96	     * dependency.
97	     *
98	     * The file produced contains:
99	     *   [Content_Types].xml
100	     *   _rels/.rels
101	     *   xl/workbook.xml
102	     *   xl/_rels/workbook.xml.rels
103	     *   xl/worksheets/sheet1.xml
104	     *
105	     * Accountants using LibreOffice / Excel / Google Sheets can open the
106	     * returned bytes directly.
107	     */
108	    private static function toXlsx(array $rows, array $headers): string
109	    {
110	        // Build sheet rows as inline string XML.
111	        $rowXml = '';
112	        $rowNum = 1;
113	
114	        // Header row
115	        $cells = '';
116	        $col = 'A';
117	        foreach ($headers as $h) {
118	            $cells .= '<c r="' . $col . $rowNum . '" t="inlineStr"><is><t>'
119	                . self::xmlEscape((string)$h) . '</t></is></c>';
120	            $col++;
121	        }
122	        $rowXml .= '<row r="' . $rowNum . '">' . $cells . '</row>';
123	        $rowNum++;
124	
125	        // Data rows
126	        foreach ($rows as $row) {
127	            $cells = '';
128	            $col = 'A';
129	            foreach ($headers as $h) {
130	                $val = (string)($row[$h] ?? '');
131	                $cells .= '<c r="' . $col . $rowNum . '" t="inlineStr"><is><t>'
132	                    . self::xmlEscape($val) . '</t></is></c>';
133	                $col++;
134	            }
135	            $rowXml .= '<row r="' . $rowNum . '">' . $cells . '</row>';
136	            $rowNum++;
137	        }
138	
139	        $sheetXml = '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>'
140	            . '<worksheet xmlns="http://schemas.openxmlformats.org/spreadsheetml/2006/main">'
141	            . '<sheetData>' . $rowXml . '</sheetData>'
142	            . '</worksheet>';
143	
144	        $workbookXml = '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>'
145	            . '<workbook xmlns="http://schemas.openxmlformats.org/spreadsheetml/2006/main"'
146	            . ' xmlns:r="http://schemas.openxmlformats.org/officeDocument/2006/relationships">'
147	            . '<sheets><sheet name="Export" sheetId="1" r:id="rId1"/></sheets>'
148	            . '</workbook>';
149	
150	        $workbookRels = '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>'
151	            . '<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">'
152	            . '<Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/worksheet" Target="worksheets/sheet1.xml"/>'
153	            . '</Relationships>';
154	
155	        $rootRels = '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>'
156	            . '<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">'
157	            . '<Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="xl/workbook.xml"/>'
158	            . '</Relationships>';
159	
160	        $contentTypes = '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>'
161	            . '<Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types">'
162	            . '<Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/>'
163	            . '<Default Extension="xml" ContentType="application/xml"/>'
164	            . '<Override PartName="/xl/workbook.xml" ContentType="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet.main+xml"/>'
165	            . '<Override PartName="/xl/worksheets/sheet1.xml" ContentType="application/vnd.openxmlformats-officedocument.spreadsheetml.worksheet+xml"/>'
166	            . '</Types>';
167	
168	        // Assemble the zip in-memory via a temporary file (ZipArchive needs a path)
169	        $tmp = tempnam(sys_get_temp_dir(), 'xlsx_');
170	        if ($tmp === false) {
171	            throw new \RuntimeException('Unable to allocate temporary xlsx file');
172	        }
173	        $zip = new \ZipArchive();
174	        if ($zip->open($tmp, \ZipArchive::OVERWRITE) !== true) {
175	            @unlink($tmp);
176	            throw new \RuntimeException('Unable to open xlsx zip for writing');
177	        }
178	        $zip->addFromString('[Content_Types].xml', $contentTypes);
179	        $zip->addFromString('_rels/.rels', $rootRels);
180	        $zip->addFromString('xl/workbook.xml', $workbookXml);
181	        $zip->addFromString('xl/_rels/workbook.xml.rels', $workbookRels);
182	        $zip->addFromString('xl/worksheets/sheet1.xml', $sheetXml);
183	        $zip->close();
184	
185	        $bytes = (string)file_get_contents($tmp);
186	        @unlink($tmp);
187	        return $bytes;
188	    }
189	
190	    private static function xmlEscape(string $s): string
191	    {
192	        return htmlspecialchars($s, ENT_XML1 | ENT_QUOTES, 'UTF-8');
193	    }
194	}
