8	/**
9	 * Duplicate detection service for entity profiles.
10	 * Flags potential duplicates based on: display_name + address + last4 of ID/license.
11	 * Does NOT block saves — creates a duplicate_flags record for review.
12	 */
13	class DuplicateService
14	{
15	    /**
16	     * Check for duplicates of the given profile data.
17	     * Skips the profile's own ID (for updates).
18	     * Returns array of matching profile IDs, or empty.
19	     */
20	    public static function findMatches(
21	        string $displayName,
22	        string $address,
23	        ?string $idLast4,
24	        ?string $licenseLast4,
25	        ?int $excludeId = null
26	    ): array {
27	        $query = Db::table('entity_profiles')
28	            ->where('display_name', $displayName)
29	            ->where('address', $address)
30	            ->where('status', 'active');
31	
32	        if ($excludeId) {
33	            $query->where('id', '<>', $excludeId);
34	        }
35	
36	        // Must match at least one of id_last4 or license_last4
37	        $hasIdentifier = false;
38	        if (!empty($idLast4)) {
39	            $query->where('id_last4', $idLast4);
40	            $hasIdentifier = true;
41	        }
42	        if (!empty($licenseLast4) && !$hasIdentifier) {
43	            $query->where('license_last4', $licenseLast4);
44	            $hasIdentifier = true;
45	        }
46	
47	        // If no identifier provided, match on name + address only
48	        // (still flag for review)
49	        if (!$hasIdentifier && (empty($idLast4) && empty($licenseLast4))) {
50	            return [];
51	        }
52	
53	        return $query->column('id');
54	    }
55	
56	    /**
57	     * Create duplicate flag records for a profile against its matches.
58	     * Returns the number of flags created.
59	     */
60	    public static function flagDuplicates(int $profileId, array $matchingIds): int
61	    {
62	        $count = 0;
63	        foreach ($matchingIds as $matchId) {
64	            // Avoid duplicate flags (check both directions)
65	            $existing = Db::table('duplicate_flags')
66	                ->where(function ($q) use ($profileId, $matchId) {
67	                    $q->where('left_profile_id', $profileId)->where('right_profile_id', $matchId);
68	                })
69	                ->whereOr(function ($q) use ($profileId, $matchId) {
70	                    $q->where('left_profile_id', $matchId)->where('right_profile_id', $profileId);
71	                })
72	                ->where('status', 'open')
73	                ->find();
74	
75	            if (!$existing) {
76	                Db::table('duplicate_flags')->insert([
77	                    'left_profile_id'  => $profileId,
78	                    'right_profile_id' => $matchId,
79	                    'match_basis'      => 'name+address+last4',
80	                    'status'           => 'open',
81	                ]);
82	                $count++;
83	            }
84	        }
85	        return $count;
86	    }
87	}
