299	     * Fetch a CAPTCHA challenge and compute the answer.
300	     * Used to auto-inject captcha credentials on /auth/register and /auth/login.
301	     */
302	    private function autoCaptcha(): array
303	    {
304	        $ch = curl_init($this->baseUrl . '/auth/captcha');
305	        curl_setopt_array($ch, [CURLOPT_RETURNTRANSFER => true, CURLOPT_TIMEOUT => 5]);
306	        $raw = curl_exec($ch); curl_close($ch);
307	        $d = json_decode($raw, true) ?: [];
308	        if (preg_match('/(-?\d+)\s*([+\-*])\s*(-?\d+)/', $d['question'] ?? '', $m)) {
309	            $a = (int)$m[1]; $op = $m[2]; $b = (int)$m[3];
310	            $ans = match ($op) { '+' => $a + $b, '-' => $a - $b, '*' => $a * $b, default => 0 };
311	            return ['captcha_id' => $d['challenge_id'] ?? '', 'captcha_answer' => (string)$ans];
312	        }
313	        return ['captcha_id' => '', 'captcha_answer' => ''];
314	    }
