2	/**
3	 * Standalone scheduler loop.
4	 * Runs registered background jobs periodically.
5	 *
6	 * Jobs executed:
7	 *  - InvoiceService::markOverdue      (overdue invoice updater)
8	 *  - JobService::expireDelegations    (delegation expiry revoker)
9	 *  - JobService::cleanRetention       (message retention cleaner)
10	 *
11	 * The loop polls every SCHEDULER_INTERVAL_SECONDS seconds (default 900 = 15 min).
12	 * Started by docker-entrypoint.sh in the background so jobs are wired at
13	 * container startup, not only when an admin clicks "Run jobs".
14	 */
15	
16	require __DIR__ . '/../vendor/autoload.php';
17	
18	use think\App;
19	use app\service\JobService;
20	use app\service\LogService;
21	
22	// Bootstrap the ThinkPHP app so services have DB access
23	$app = new App();
24	$app->initialize();
25	
26	$interval = (int)(getenv('SCHEDULER_INTERVAL_SECONDS') ?: 900);
27	if ($interval < 60) $interval = 60; // safety floor
28	
29	fwrite(STDERR, "[scheduler] started, interval={$interval}s\n");
30	
31	while (true) {
32	    try {
33	        $traceId = 'sched-' . bin2hex(random_bytes(6));
34	        $results = JobService::runAll($traceId);
35	        fwrite(STDERR, "[scheduler] tick: " . json_encode($results) . "\n");
36	    } catch (\Throwable $e) {
37	        fwrite(STDERR, "[scheduler] error: " . $e->getMessage() . "\n");
38	    }
39	    sleep($interval);
40	}
