                    break;
                case 'number':
                    html += '<input type="number" name="ef_' + esc(d.field_key) + '" placeholder="' + esc(d.field_label) + '" class="layui-input">';
                    break;
                case 'date':
                    html += '<input type="date" name="ef_' + esc(d.field_key) + '" class="layui-input">';
                    break;
                case 'select':
