     * gives the same value (idempotent).
     */
    public function testRepeatedJobRunDoesNotDoubleFee(): void
    {
        $prof = $this->post('/entities', [
            'entity_type' => 'farmer', 'display_name' => 'IdempLate ' . microtime(true), 'address' => 'S',
