4	namespace tests\api;
5	
6	use PHPUnit\Framework\TestCase;
7	
8	/**
9	 * Remediation: Issue I-09 (v3 Blocking)
10	 *
11	 * Public /auth/register must NOT allow self-assignment of `system_admin`.
12	 * Admin accounts may only be minted via the authenticated POST /admin/users
13	 * endpoint by an existing system_admin (bootstrap/invite model).
14	 *
15	 * Happy/boundary coverage:
16	 *  - Anonymous register with role=system_admin               => 403 FORBIDDEN
17	 *  - Anonymous register with role=farmer                     => 201 (regression guard)
18	 *  - Admin calls /admin/users to create system_admin         => 201
19	 *  - Farmer calls /admin/users                               => 403 (route-level RBAC)
20	 *  - Unauthenticated /admin/users                            => 401
21	 *  - createByAdmin with bad role still 400 (general validation)
22	 */
23	class PrivilegeEscalationTest extends TestCase
24	{
25	    private string $baseUrl;
26	
27	    protected function setUp(): void
28	    {
29	        $this->baseUrl = getenv('API_BASE_URL') ?: 'http://localhost:8000';
30	    }
31	
32	    public function testPublicRegisterCannotSelfAssignSystemAdmin(): void
33	    {
34	        $resp = $this->post('/auth/register', [
35	            'username'        => 'evil_' . bin2hex(random_bytes(4)),
36	            'password'        => 'SecureP@ss12345',
37	            'role'            => 'system_admin',
38	            'geo_scope_level' => 'county',
39	            'geo_scope_id'    => 1,
40	        ]);
41	        $this->assertEquals(403, $resp['status'], 'system_admin self-register must be blocked');
42	        $this->assertEquals('FORBIDDEN', $resp['data']['code'] ?? '');
43	        $this->assertStringContainsString('system_admin', strtolower($resp['data']['message'] ?? ''));
44	    }
45	
46	    public function testPublicRegisterStillAllowsFarmer(): void
47	    {
48	        $resp = $this->post('/auth/register', [
49	            'username'        => 'good_' . bin2hex(random_bytes(4)),
50	            'password'        => 'SecureP@ss12345',
51	            'role'            => 'farmer',
52	            'geo_scope_level' => 'village',
53	            'geo_scope_id'    => 3,
54	        ]);
55	        $this->assertEquals(201, $resp['status'], 'non-admin register must still succeed');
56	        $this->assertEquals('farmer', $resp['data']['role'] ?? '');
57	    }
58	
59	    public function testPublicRegisterStillAllowsEnterpriseAndCollective(): void
60	    {
61	        foreach (['enterprise', 'collective'] as $role) {
62	            $resp = $this->post('/auth/register', [
63	                'username'        => 'nonadm_' . $role . '_' . bin2hex(random_bytes(4)),
64	                'password'        => 'SecureP@ss12345',
65	                'role'            => $role,
66	                'geo_scope_level' => 'village',
67	                'geo_scope_id'    => 3,
68	            ]);
69	            $this->assertEquals(201, $resp['status'], "$role must still register");
70	        }
71	    }
72	
73	    public function testAdminCanCreateSystemAdminViaAdminUsers(): void
74	    {
75	        // Bootstrap: there is at least one admin already (created by other
76	        // test classes). If not, we have to provision one via the same
77	        // admin endpoint — but that's a chicken-and-egg problem, so we
78	        // fall back to a DB-level bootstrap only for this test.
79	        $admin = $this->getOrCreateBootstrapAdmin();
80	
