191	    {
192	        $ch = curl_init($this->baseUrl . '/auth/captcha');
193	        curl_setopt_array($ch, [CURLOPT_RETURNTRANSFER => true, CURLOPT_TIMEOUT => 5]);
194	        $raw = curl_exec($ch); curl_close($ch);
195	        $d = json_decode($raw, true) ?: [];
196	        if (preg_match('/(-?\d+)\s*([+\-*])\s*(-?\d+)/', $d['question'] ?? '', $m)) {
197	            $a = (int)$m[1]; $op = $m[2]; $b = (int)$m[3];
198	            $ans = match ($op) { '+' => $a + $b, '-' => $a - $b, '*' => $a * $b, default => 0 };
199	            return ['captcha_id' => $d['challenge_id'] ?? '', 'captcha_answer' => (string)$ans];
200	        }
201	        return ['captcha_id' => '', 'captcha_answer' => ''];
202	    }
