            })
            ->whereOr(function ($q) use ($sourceId, $targetId) {
                $q->where('left_profile_id', $targetId)->where('right_profile_id', $sourceId);
            })
            ->update(['status' => 'merged']);

        LogService::info('entity_merged', [
            'source_id' => $sourceId,
